const items = $input.all().map(i => i.json).filter(x => x.url && x.title);
items.sort((a,b) => (b.isoDate||'').localeCompare(a.isoDate||''));
const capped = items.slice(0, 60);
const candidates = capped.map((x,i) => ({ idx: i, title: x.title, snippet: x.snippet, source: x.source, hint: x.industry, url: x.url, isoDate: x.isoDate }));
if (candidates.length === 0) return [];
const z = $now.setZone('Europe/Berlin');
const today = z.toFormat('yyyy-LL-dd');
const yest = z.minus({ days: 1 }).toFormat('yyyy-LL-dd');
let sentRows = [];
try { sentRows = $('Aggregate Recent').first().json.sent || []; } catch(e) { sentRows = []; }
const recent_sent = (Array.isArray(sentRows) ? sentRows : [])
  .filter(r => r && (r.day === today || r.day === yest) && r.title)
  .map(r => ({ title: r.title, source: r.source }))
  .slice(0, 80);
return [{ json: { candidates, recent_sent, count: candidates.length } }];

const out = $json.output || {};
const results = Array.isArray(out.results) ? out.results : [];
const cand = $('Build Claude Input').first().json.candidates || [];
const byIdx = {}; cand.forEach(c => { byIdx[c.idx] = c; });
const z = $now.setZone('Europe/Berlin');
const day = z.toFormat('yyyy-LL-dd');
const run = z.hour < 12 ? 'morning' : 'evening';
const sentAt = $now.toISO();
const esc = s => (s||'').toString().replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const labels = { 'AI':'🟢 AI', 'AI+Game':'🎮 AI+GAME', 'GameDev':'🕹 GAMEDEV', 'Investments':'💰 INVEST', 'Research':'🔬 RESEARCH' };
const bad = /ALREADY_SENT|ОТКЛОН|дубл|\bDROP\b|duplicate/i;
const outItems = [];
for (const r of results) {
  if (!r || r.keep !== true) continue;
  const c = byIdx[r.idx]; if (!c) continue;
  const summary = (r.summary_ru || '').toString().trim();
  if (!summary || bad.test(summary)) continue;
  const industry = r.industry || c.hint || 'AI';
  const title = (r.title || c.title || '').toString().trim();
  const tag = labels[industry] || ('📰 ' + industry);
  const safeUrl = (c.url||'').toString().replace(/&/g,'&amp;').replace(/"/g,'%22');
  const message = tag + ' · <b>' + esc(title) + '</b>\n\n' + esc(summary) + '\n\n🔗 <a href="' + safeUrl + '">Source</a>';
  outItems.push({ json: { url: c.url, title, industry, source: c.source, summary_ru: summary, day, run, sent_at: sentAt, message } });
}
return outItems;

const all = $input.all().map(i => i.json);
all.sort((a,b) => (a.pinned_at||'').localeCompare(b.pinned_at||''));
const excess = all.slice(0, Math.max(0, all.length - 5));
return excess.map(r => ({ json: r }));

const sources = $input.all().map(i => i.json);
const UA = 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/126.0.0.0 Safari/537.36';
const dec = (s) => (s||'').replace(/<!\[CDATA\[([^]*?)\]\]>/g,'$1').replace(/&#(\d+);/g, (m,n)=>String.fromCharCode(parseInt(n,10))).replace(/&lt;/g,'<').replace(/&gt;/g,'>').replace(/&quot;/g,'"').replace(/&apos;/g,"'").replace(/&nbsp;/g,' ').replace(/&amp;/g,'&');
const strip = (s) => dec(s||'').replace(/<[^>]*>/g,' ').replace(/\s+/g,' ').trim();
const pick = (b, tags) => { for (const t of tags) { const m = b.match(new RegExp('<'+t+'[^>]*>([^]*?)<\/'+t+'>','i')); if (m) return m[1]; } return ''; };
const out = [];
for (const s of sources) {
  let body='';
  try { const res = await this.helpers.httpRequest({ url:s.feed_url, returnFullResponse:true, timeout:20000, headers:{ 'User-Agent':UA, 'Accept':'application/rss+xml, application/atom+xml, application/xml, text/xml, */*', 'Accept-Language':'en-US,en;q=0.9' } }); body=(res.body||'').toString(); } catch(e) { continue; }
  const isAtom = /<entry[\s>]/.test(body) && !/<item[\s>]/.test(body);
  let blocks = body.match(isAtom ? /<entry[\s>][^]*?<\/entry>/gi : /<item[\s>][^]*?<\/item>/gi) || [];
  blocks = blocks.slice(0, 25);
  for (const b of blocks) {
    const title = strip(pick(b,['title']));
    let link = strip(pick(b,['link']));
    if (!link) { const lm = b.match(/<link[^>]*href=["']([^"']+)["']/i); if (lm) link = lm[1]; }
    if (!link) link = strip(pick(b,['guid','id']));
    const rawd = strip(pick(b,['pubDate','published','updated','dc:date','date']));
    let iso=null; if (rawd) { const d=new Date(rawd); if (!isNaN(d.getTime())) iso=d.toISOString(); }
    let snip = strip(pick(b,['description','summary','content'])); if (snip.length>300) snip=snip.slice(0,300);
    let url=(link||'').trim();
    try { const u=new URL(url); u.hash=''; u.search=''; url=u.toString().replace(/\/$/,''); } catch(e){}
    if (!title || !url) continue;
    out.push({ json:{ title, url, isoDate:iso, snippet:snip, source:s.name, industry:s.industry } });
  }
}
return out;

const UA = 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/126.0.0.0 Safari/537.36';
const pages = ['https://itch.io/games/newest/tag-artificial-intelligence', 'https://itch.io/games/newest/tag-artificial-intelligence?page=2'];
const out = [];
const seen = new Set();
for (const purl of pages) {
  let body = '';
  try { const res = await this.helpers.httpRequest({ url: purl, returnFullResponse: true, timeout: 20000, headers: { 'User-Agent': UA, 'Accept-Language': 'en-US,en;q=0.9' } }); body = (res.body || '').toString(); } catch (e) { continue; }
  const re = /<a\b[^>]*class="title game_link"[^>]*>([^]*?)<\/a>/gi;
  let m;
  while ((m = re.exec(body))) {
    const hm = m[0].match(/href="([^"]+)"/i);
    if (!hm) continue;
    let url = hm[1];
    try { const u = new URL(url); u.hash=''; u.search=''; url = u.toString().replace(/\/$/,''); } catch(e) {}
    if (!/\.itch\.io\//.test(url)) continue;
    if (seen.has(url)) continue; seen.add(url);
    const title = m[1].replace(/<[^>]*>/g,'').replace(/&amp;/g,'&').replace(/&#39;/g,"'").replace(/&#(\d+);/g,(x,n)=>String.fromCharCode(parseInt(n,10))).replace(/\s+/g,' ').trim();
    out.push({ json: { url, title } });
  }
  if (out.length >= 70) break;
}
return out;

const UA = 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/126.0.0.0 Safari/537.36';
const games = $input.all().map(i => i.json).slice(0, 40);
const clean = (s) => (s||'').replace(/<[^>]*>/g,' ').replace(/&amp;/g,'&').replace(/&quot;/g,'"').replace(/&#39;/g,"'").replace(/&#(\d+);/g,(x,n)=>String.fromCharCode(parseInt(n,10))).replace(/\s+/g,' ').trim();
const fetchOne = async (g) => {
  let b = '';
  try { const r = await this.helpers.httpRequest({ url: g.url, returnFullResponse: true, timeout: 8000, headers: { 'User-Agent': UA, 'Accept-Language': 'en-US,en;q=0.9' } }); b = (r.body||'').toString(); } catch (e) { return null; }
  if (/content is marked as adult|tag-nsfw|tag-adult/i.test(b)) return null;
  let desc = '';
  const di = b.indexOf('formatted_description');
  if (di >= 0) { const gt = b.indexOf('>', di); desc = clean(b.slice(gt+1, di+4000)); }
  if (!desc) { const om = b.match(/<meta\s+(?:property="og:description"|name="description")\s+content="([^"]*)"/i); desc = clean(om ? om[1] : ''); }
  const mi = desc.indexOf('More information'); if (mi > 20) desc = desc.slice(0, mi).trim();
  desc = desc.slice(0, 1000);
  const tags = (b.match(/\/games\/tag-[a-z0-9-]+/gi) || []).map(t => t.replace('/games/tag-','')).filter((v,i,a)=>a.indexOf(v)===i).slice(0, 15).join(', ');
  return { url: g.url, title: g.title, desc, tags };
};
const out = [];
const CONC = 10;
for (let i = 0; i < games.length; i += CONC) {
  const chunk = games.slice(i, i + CONC);
  const res = await Promise.all(chunk.map(fetchOne));
  for (const r of res) { if (r) out.push({ json: r }); }
}
return out;

const items = $input.all().map(i => i.json).filter(x => x.url && x.title);
const candidates = items.slice(0, 40).map((x,i) => ({ idx: i, title: x.title, desc: x.desc, tags: x.tags, url: x.url }));
if (candidates.length === 0) return [];
return [{ json: { candidates, count: candidates.length } }];

parameters.text:
=You analyze indie games from itch.io to find games that USE AI as an in-game TECHNOLOGY at runtime AND run that AI LOCALLY / on-device (offline), NOT via cloud APIs.

KEEP (used_ai = true) ONLY when BOTH conditions hold:
1) AI is part of how the game actually works or is played — e.g. LLM / chatbot NPCs the player talks to in natural language, AI-driven dialogue or storytelling, content generated live by ML models, voice AI interaction, or ML models powering mechanics; AND
2) that AI runs LOCALLY on the player's machine / on-device / offline. Signals of local: "local model", "runs locally", "offline", "on-device", GGUF, llama.cpp, Ollama, LM Studio, koboldcpp, bundled or downloadable model, local inference, "no internet / no API key required". If the game clearly offers BOTH local and cloud options, KEEP it (local is supported).

DO NOT count (used_ai = false):
- AI that runs in the CLOUD / via an online API (OpenAI, Anthropic, Gemini, OpenRouter, "requires API key", "needs internet for the AI", server-side) when there is NO local option;
- cases where you cannot tell whether the AI is local or cloud — if there is no concrete evidence of LOCAL/on-device AI, set used_ai = false (when in doubt, false);
- games merely MADE WITH AI-generated assets (art, music, textures) — asset generation does NOT qualify;
- classic game AI (pathfinding, finite-state-machine enemies, behavior trees, "smart" bots);
- marketing buzzwords with no real AI technology behind them.

Read each candidate's title, desc (developer description) and tags carefully for explicit mentions of LOCAL / on-device AI. For used_ai = true, write a short Russian note (1 sentence, <=200 chars) stating that it is LOCAL AI and what it does in the game. Keep the original title exactly.

Return results for ALL candidates (both true and false), referencing each by idx.

CANDIDATES:
{{ JSON.stringify($json.candidates) }}

