const out = $json.output || {};
const results = Array.isArray(out.results) ? out.results : [];
const cand = $('Build itch Claude Input').first().json.candidates || [];
const z = $now.setZone('Europe/Berlin');
const day = z.toFormat('yyyy-LL-dd');
const sentAt = $now.toISO();
const esc = s => (s||'').toString().replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const outItems = [];
for (const c of cand) {
  const r = results.find(x => x && x.idx === c.idx) || {};
  const used = r.used_ai === true;
  const title = (r.title || c.title || '').toString().trim();
  const note = (r.ai_note || '').toString().trim();
  const safeUrl = (c.url||'').toString().replace(/&/g,'&amp;').replace(/"/g,'%22');
  const message = used ? ('🎮 itch.io · <b>' + esc(title) + '</b>\n\n' + esc(note) + '\n\n🔗 <a href="' + safeUrl + '">Source</a>') : '';
  outItems.push({ json: { url: c.url, title, used_ai: used, ai_note: note, day, sent_at: sentAt, message } });
}
return outItems;

const UA = 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/126.0.0.0 Safari/537.36';
const items = $input.all().map(i => i.json);
const getImg = async (it) => {
  let image = '';
  try { const r = await this.helpers.httpRequest({ url: it.url, returnFullResponse: true, timeout: 8000, headers: { 'User-Agent': UA } }); const b = (r.body||'').toString(); const m = b.match(/<meta[^>]+property="og:image"[^>]+content="([^"]+)"/i) || b.match(/<meta[^>]+content="([^"]+)"[^>]+property="og:image"/i) || b.match(/<meta[^>]+name="twitter:image(?::src)?"[^>]+content="([^"]+)"/i); image = m ? m[1] : ''; } catch (e) {}
  return Object.assign({}, it, { image });
};
const out = [];
const CONC = 8;
for (let i = 0; i < items.length; i += CONC) { const ch = items.slice(i, i + CONC); const res = await Promise.all(ch.map(getImg)); for (const r of res) out.push({ json: r }); }
return out;
